const q = $.input.chatQuestion || 'What are the top 3 trends in AI for 2026?';
const summarizeText = $.input.textToSummarize || 'Artificial intelligence has rapidly evolved from a niche research topic to a mainstream technology that impacts every industry. In 2026, we see AI being used in healthcare for drug discovery, in finance for fraud detection, in education for personalized learning, and in manufacturing for predictive maintenance. The global AI market is expected to exceed $500 billion, with generative AI leading growth.';
const translateText = $.input.translateText || 'Hello, how are you today?';
const translateTo = $.input.translateTo || 'Spanish, French, Japanese';
const codeTask = $.input.codeTask || 'Write a Python function that checks if a string is a palindrome';
const extractText = $.input.textToExtract || 'John Smith, CEO of TechCorp (john@techcorp.com, +1-555-0123) met with Sarah Jones from InnovateLabs on March 15, 2026 to discuss a $2.5M partnership deal for AI-powered analytics.';

let prompt = 'You are a versatile AI assistant. Perform these 5 tasks and return results for each.

';
prompt += 'TASK 1 - CHAT Q&A:
Question: ' + q + '

';
prompt += 'TASK 2 - SUMMARIZE:
Text: ' + summarizeText + '

';
prompt += 'TASK 3 - TRANSLATE to ' + translateTo + ':
Text: ' + translateText + '

';
prompt += 'TASK 4 - CODE GENERATION:
Task: ' + codeTask + '

';
prompt += 'TASK 5 - DATA EXTRACTION:
Text: ' + extractText + '

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "chat": { "question": "", "answer": "" },
';
prompt += '  "summary": { "original": "", "summary": "", "keyPoints": [] },
';
prompt += '  "translations": [{ "language": "", "translation": "" }],
';
prompt += '  "code": { "task": "", "language": "", "code": "", "explanation": "" },
';
prompt += '  "extraction": { "people": [{ "name": "", "role": "", "organization": "" }], "emails": [], "phones": [], "amounts": [], "dates": [], "summary": "" }
';
prompt += '}';
return { prompt };

let raw = $.steps.aiShowcase.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { chat: { question: '', answer: raw.slice(0, 500) }, summary: { summary: '' }, translations: [], code: { code: '' }, extraction: { people: [], emails: [], phones: [], amounts: [], dates: [] } }; }

const ai = $.steps.parseAI.output;
const rows = [];
rows.push(['Chat Q&A', ai.chat?.question || '', (ai.chat?.answer || '').slice(0, 500)]);
rows.push(['Summary', '', (ai.summary?.summary || '').slice(0, 500)]);
const translations = ai.translations || [];
translations.forEach(function(t) {
  rows.push(['Translation (' + t.language + ')', '', t.translation || '']);
});
rows.push(['Code Generation', ai.code?.language || '', (ai.code?.code || '').slice(0, 500)]);
rows.push(['Data Extraction', '', (ai.extraction?.summary || '').slice(0, 500)]);
return { rows: rows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Capabilities Showcase (5-in-1)', emoji: true } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*1. Chat Q&A*\n_Q: ' + (ai.chat?.question || '').slice(0, 100) + '_\nA: ' + (ai.chat?.answer || '').slice(0, 400) } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*2. Summary*\n' + (ai.summary?.summary || '').slice(0, 400) } });
blocks.push({ type: 'divider' });

const translations = ai.translations || [];
let transText = '*3. Translations*\n';
translations.slice(0, 3).forEach(function(t) { transText += '*' + t.language + ':* ' + t.translation + '\n'; });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: transText.slice(0, 1800) } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*4. Code*\n```' + (ai.code?.code || '').slice(0, 500) + '```' } });
blocks.push({ type: 'divider' });

let extractText = '*5. Data Extraction*\n';
const people = ai.extraction?.people || [];
if (people.length > 0) extractText += 'People: ' + people.map(function(p) { return p.name + ' (' + p.role + ')'; }).join(', ') + '\n';
const emails = ai.extraction?.emails || [];
if (emails.length > 0) extractText += 'Emails: ' + emails.join(', ') + '\n';
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: extractText.slice(0, 1800) } });

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Full results in Google Sheets | Powered by Claude AI' }] });
const fallbackText = 'AI 5-in-1 Showcase: Chat, Summary, Translate, Code, Extract';
return { blocks, fallbackText };
